optionsVector := []vectorstores.Option{
	vectorstores.WithScoreThreshold(0.60),
}

retriever := vectorstores.ToRetriever(&store, 1, optionsVector...)

// Loads OpenAI API key from environment
openaiApiKey := os.Getenv("OPENAI_API_KEY")
if openaiApiKey == "" {
